contracts/BTNGCustody.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "./BTNGGoldToken.sol";

/**
 * @title BTNG Custody Contract
 * @dev Manages gold reserves custody and minting/redemption operations
 * Integrates with oracles for gold reserve verification
 */
contract BTNGCustody is Ownable, Pausable, ReentrancyGuard {
    // Events
    event GoldDeposited(string batchId, uint256 grams, address custodian);
    event GoldWithdrawn(string batchId, uint256 grams, address custodian);
    event MintRequest(address indexed requester, uint256 amount, string batchId);
    event RedemptionRequest(address indexed requester, uint256 amount, string redemptionId);
    event OracleUpdated(address indexed oldOracle, address indexed newOracle);
    event CustodianAdded(address indexed custodian);
    event CustodianRemoved(address indexed custodian);

    // Structs
    struct GoldBatch {
        string batchId;
        uint256 grams;
        address custodian;
        uint256 timestamp;
        bool isDeposited;
        bool isWithdrawn;
        string certificateHash; // IPFS hash of gold certificate
    }

    struct RedemptionRequestData {
        address requester;
        uint256 amount;
        string redemptionId;
        uint256 timestamp;
        bool isProcessed;
        string deliveryAddress;
    }

    // State variables
    BTNGGoldToken public goldToken;
    address public oracle; // Oracle for gold reserve verification

    mapping(string => GoldBatch) public goldBatches;
    mapping(string => RedemptionRequestData) public redemptionRequests;
    mapping(address => bool) public authorizedCustodians;

    uint256 public totalGoldReserves; // Total grams in custody
    uint256 public minCustodyThreshold = 1000; // Minimum grams for operations

    // Modifiers
    modifier onlyCustodian() {
        require(authorizedCustodians[msg.sender], "BTNGCustody: caller is not authorized custodian");
        _;
    }

    modifier onlyOracle() {
        require(msg.sender == oracle, "BTNGCustody: caller is not oracle");
        _;
    }

    modifier sufficientReserves(uint256 grams) {
        require(totalGoldReserves >= grams, "BTNGCustody: insufficient gold reserves");
        require(totalGoldReserves - grams >= minCustodyThreshold, "BTNGCustody: would violate minimum threshold");
        _;
    }

    /**
     * @dev Constructor
     * @param _goldToken Address of the BTNG Gold Token contract
     * @param _oracle Address of the oracle contract
     */
    constructor(address _goldToken, address _oracle) Ownable(msg.sender) {
        require(_goldToken != address(0), "BTNGCustody: invalid gold token address");
        require(_oracle != address(0), "BTNGCustody: invalid oracle address");

        goldToken = BTNGGoldToken(_goldToken);
        oracle = _oracle;

        // Add deployer as initial custodian
        authorizedCustodians[msg.sender] = true;
    }

    /**
     * @dev Deposit gold into custody (called by authorized custodians)
     * @param batchId Unique batch identifier
     * @param grams Amount of gold in grams
     * @param certificateHash IPFS hash of gold certificate
     */
    function depositGold(
        string calldata batchId,
        uint256 grams,
        string calldata certificateHash
    )
        external
        onlyCustodian
        whenNotPaused
        nonReentrant
    {
        require(bytes(batchId).length > 0, "BTNGCustody: invalid batch ID");
        require(grams > 0, "BTNGCustody: grams must be positive");
        require(!goldBatches[batchId].isDeposited, "BTNGCustody: batch already deposited");

        goldBatches[batchId] = GoldBatch({
            batchId: batchId,
            grams: grams,
            custodian: msg.sender,
            timestamp: block.timestamp,
            isDeposited: true,
            isWithdrawn: false,
            certificateHash: certificateHash
        });

        totalGoldReserves += grams;

        emit GoldDeposited(batchId, grams, msg.sender);
    }

    /**
     * @dev Withdraw gold from custody for redemption
     * @param batchId Batch to withdraw
     */
    function withdrawGold(string calldata batchId)
        external
        onlyCustodian
        whenNotPaused
        nonReentrant
    {
        GoldBatch storage batch = goldBatches[batchId];
        require(batch.isDeposited, "BTNGCustody: batch not deposited");
        require(!batch.isWithdrawn, "BTNGCustody: batch already withdrawn");
        require(batch.custodian == msg.sender, "BTNGCustody: not batch custodian");

        batch.isWithdrawn = true;
        totalGoldReserves -= batch.grams;

        emit GoldWithdrawn(batchId, batch.grams, msg.sender);
    }

    /**
     * @dev Request minting of gold-backed tokens
     * @param amount Amount of tokens to mint
     * @param batchId Gold batch to back the minting
     */
    function requestMint(uint256 amount, string calldata batchId)
        external
        whenNotPaused
        nonReentrant
    {
        require(amount > 0, "BTNGCustody: amount must be positive");

        GoldBatch storage batch = goldBatches[batchId];
        require(batch.isDeposited && !batch.isWithdrawn, "BTNGCustody: invalid gold batch");
        require(batch.grams >= amount / 10**18, "BTNGCustody: insufficient gold in batch");

        emit MintRequest(msg.sender, amount, batchId);
    }

    /**
     * @dev Execute minting (called by oracle after verification)
     * @param to Address to mint tokens to
     * @param amount Amount to mint
     * @param batchId Gold batch backing the mint
     */
    function executeMint(
        address to,
        uint256 amount,
        string calldata batchId
    )
        external
        onlyOracle
        whenNotPaused
        sufficientReserves(amount / 10**18)
        nonReentrant
    {
        GoldBatch storage batch = goldBatches[batchId];
        require(batch.isDeposited && !batch.isWithdrawn, "BTNGCustody: invalid gold batch");

        uint256 goldGrams = amount / 10**18;
        require(batch.grams >= goldGrams, "BTNGCustody: insufficient gold in batch");

        // Update batch (partial usage)
        batch.grams -= goldGrams;

        // Mint tokens
        goldToken.mintGoldBacked(to, amount, batchId, goldGrams);
    }

    /**
     * @dev Request gold redemption
     * @param amount Amount of tokens to redeem
     * @param redemptionId Unique redemption identifier
     * @param deliveryAddress Physical delivery address
     */
    function requestRedemption(
        uint256 amount,
        string calldata redemptionId,
        string calldata deliveryAddress
    )
        external
        whenNotPaused
        nonReentrant
    {
        require(amount > 0, "BTNGCustody: amount must be positive");
        require(bytes(redemptionId).length > 0, "BTNGCustody: invalid redemption ID");
        require(bytes(deliveryAddress).length > 0, "BTNGCustody: invalid delivery address");
        require(!redemptionRequests[redemptionId].isProcessed, "BTNGCustody: redemption already processed");

        redemptionRequests[redemptionId] = RedemptionRequestData({
            requester: msg.sender,
            amount: amount,
            redemptionId: redemptionId,
            timestamp: block.timestamp,
            isProcessed: false,
            deliveryAddress: deliveryAddress
        });

        emit RedemptionRequest(msg.sender, amount, redemptionId);
    }

    /**
     * @dev Execute redemption (called by custodian after processing)
     * @param redemptionId Redemption to process
     */
    function executeRedemption(string calldata redemptionId)
        external
        onlyCustodian
        whenNotPaused
        nonReentrant
    {
        RedemptionRequestData storage request = redemptionRequests[redemptionId];
        require(!request.isProcessed, "BTNGCustody: redemption already processed");

        request.isProcessed = true;

        // Burn tokens (user must have approved this contract)
        goldToken.redeemGold(request.amount, redemptionId);
    }

    /**
     * @dev Add authorized custodian
     * @param custodian Address to authorize
     */
    function addCustodian(address custodian) external onlyOwner {
        require(custodian != address(0), "BTNGCustody: invalid custodian address");
        require(!authorizedCustodians[custodian], "BTNGCustody: already custodian");

        authorizedCustodians[custodian] = true;
        emit CustodianAdded(custodian);
    }

    /**
     * @dev Remove authorized custodian
     * @param custodian Address to remove
     */
    function removeCustodian(address custodian) external onlyOwner {
        require(authorizedCustodians[custodian], "BTNGCustody: not a custodian");

        authorizedCustodians[custodian] = false;
        emit CustodianRemoved(custodian);
    }

    /**
     * @dev Update oracle address
     * @param newOracle New oracle address
     */
    function updateOracle(address newOracle) external onlyOwner {
        require(newOracle != address(0), "BTNGCustody: invalid oracle address");
        address oldOracle = oracle;
        oracle = newOracle;

        emit OracleUpdated(oldOracle, newOracle);
    }

    /**
     * @dev Update minimum custody threshold
     * @param newThreshold New minimum threshold in grams
     */
    function updateMinThreshold(uint256 newThreshold) external onlyOwner {
        minCustodyThreshold = newThreshold;
    }

    /**
     * @dev Emergency pause
     */
    function pause() external onlyOwner {
        _pause();
    }

    /**
     * @dev Unpause after emergency
     */
    function unpause() external onlyOwner {
        _unpause();
    }

    /**
     * @dev Get gold batch details
     * @param batchId Batch ID to query
     */
    function getGoldBatch(string calldata batchId)
        external
        view
        returns (
            uint256 grams,
            address custodian,
            uint256 timestamp,
            bool isDeposited,
            bool isWithdrawn,
            string memory certificateHash
        )
    {
        GoldBatch memory batch = goldBatches[batchId];
        return (
            batch.grams,
            batch.custodian,
            batch.timestamp,
            batch.isDeposited,
            batch.isWithdrawn,
            batch.certificateHash
        );
    }

    /**
     * @dev Get redemption request details
     * @param redemptionId Redemption ID to query
     */
    function getRedemptionRequest(string calldata redemptionId)
        external
        view
        returns (
            address requester,
            uint256 amount,
            uint256 timestamp,
            bool isProcessed,
            string memory deliveryAddress
        )
    {
        RedemptionRequestData memory request = redemptionRequests[redemptionId];
        return (
            request.requester,
            request.amount,
            request.timestamp,
            request.isProcessed,
            request.deliveryAddress
        );
    }

    /**
     * @dev Get total gold reserves
     */
    function getTotalReserves() external view returns (uint256) {
        return totalGoldReserves;
    }

    /**
     * @dev Check if address is authorized custodian
     */
    function isCustodian(address account) external view returns (bool) {
        return authorizedCustodians[account];
    }
}

contracts/BTNGGoldDeployment.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./BTNGGoldToken.sol";
import "./BTNGCustody.sol";
import "./BTNGGoldOracle.sol";

/**
 * @title BTNG Gold System Deployment
 * @dev Deployment script for the complete BTNG Gold system
 */
contract BTNGGoldDeployment {
    BTNGGoldToken public goldToken;
    BTNGCustody public custody;
    BTNGGoldOracle public oracle;

    address public owner;
    address public oracleAddress;
    address public custodyAddress;
    address public tokenAddress;

    event SystemDeployed(
        address indexed token,
        address indexed custody,
        address indexed oracle,
        address owner
    );

    constructor() {
        owner = msg.sender;

        // Deploy Oracle first
        oracle = new BTNGGoldOracle();
        oracleAddress = address(oracle);

        // Deploy Custody with Oracle address
        custody = new BTNGCustody(address(0), oracleAddress); // Token address will be set later
        custodyAddress = address(custody);

        // Deploy Token with Custody address
        goldToken = new BTNGGoldToken(custodyAddress);
        tokenAddress = address(goldToken);

        // Update Custody contract with Token address
        custody = new BTNGCustody(tokenAddress, oracleAddress);
        custodyAddress = address(custody);

        // Update Token contract with new Custody address
        goldToken.updateCustodyContract(custodyAddress);

        // Transfer ownerships
        oracle.transferOwnership(owner);
        custody.transferOwnership(owner);
        goldToken.transferOwnership(owner);

        emit SystemDeployed(tokenAddress, custodyAddress, oracleAddress, owner);
    }

    /**
     * @dev Get all deployed contract addresses
     */
    function getContractAddresses()
        external
        view
        returns (
            address token,
            address custody_,
            address oracle_
        )
    {
        return (tokenAddress, custodyAddress, oracleAddress);
    }
}

contracts/BTNGGoldOracle.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title BTNG Gold Oracle
 * @dev Oracle contract for gold reserve data and verification
 * Provides real-time gold pricing and reserve verification
 */
contract BTNGGoldOracle is Ownable, Pausable, ReentrancyGuard {
    // Events
    event GoldPriceUpdated(uint256 oldPrice, uint256 newPrice, uint256 timestamp);
    event ReserveDataUpdated(string countryCode, uint256 newReserves);
    event OracleFeederAdded(address indexed feeder);
    event OracleFeederRemoved(address indexed feeder);
    event VerificationCompleted(bytes32 requestId, bool isValid);

    // Structs
    struct GoldPrice {
        uint256 price; // Price per gram in USD (with 8 decimals)
        uint256 timestamp;
        address updater;
    }

    struct CountryReserve {
        string countryCode;
        uint256 goldTonnes; // Gold reserves in tonnes
        uint256 lastUpdated;
        address updater;
        bool isActive;
    }

    // State variables
    mapping(address => bool) public authorizedFeeders;
    mapping(string => CountryReserve) public countryReserves;
    GoldPrice public latestGoldPrice;

    uint256 public constant PRICE_DECIMALS = 8;
    uint256 public constant MAX_PRICE_AGE = 24 hours; // Maximum age for price data
    uint256 public constant MAX_RESERVE_AGE = 7 days; // Maximum age for reserve data

    string[] public activeCountries;

    // Request tracking for verification
    mapping(bytes32 => bool) public verificationRequests;
    mapping(bytes32 => bool) public verificationResults;

    // Modifiers
    modifier onlyFeeder() {
        require(authorizedFeeders[msg.sender] || msg.sender == owner(), "BTNGGoldOracle: caller is not authorized feeder");
        _;
    }

    modifier validPrice(uint256 price) {
        require(price > 0, "BTNGGoldOracle: invalid price");
        require(price < 100000 * 10**PRICE_DECIMALS, "BTNGGoldOracle: price too high"); // Max $100k per gram
        _;
    }

    modifier validCountryCode(string calldata countryCode) {
        require(bytes(countryCode).length == 2, "BTNGGoldOracle: invalid country code");
        _;
    }

    /**
     * @dev Constructor
     */
    constructor() Ownable(msg.sender) {
        // Add deployer as initial feeder
        authorizedFeeders[msg.sender] = true;

        // Initialize with current known data (as of Feb 2026)
        _initializeCountryData();
    }

    /**
     * @dev Initialize country reserve data
     */
    function _initializeCountryData() internal {
        // Major African gold reserve holders
        _updateCountryReserve("DZ", 173600000); // Algeria: 173.6 tonnes
        _updateCountryReserve("EG", 79300000);  // Egypt: 79.3 tonnes
        _updateCountryReserve("LY", 116600000); // Libya: 116.6 tonnes
        _updateCountryReserve("ZA", 125300000); // South Africa: 125.3 tonnes
        _updateCountryReserve("GH", 8700000);   // Ghana: 8.7 tonnes
        _updateCountryReserve("NG", 21400000);  // Nigeria: 21.4 tonnes
        _updateCountryReserve("MA", 22100000);  // Morocco: 22.1 tonnes
        _updateCountryReserve("TN", 6800000);   // Tunisia: 6.8 tonnes

        // Set initial gold price (approx $60 per gram as of 2026)
        latestGoldPrice = GoldPrice({
            price: 6000000000, // $60.00 per gram
            timestamp: block.timestamp,
            updater: msg.sender
        });
    }

    /**
     * @dev Update gold price per gram
     * @param newPrice Price in USD with 8 decimals (e.g., 6000000000 = $60.00)
     */
    function updateGoldPrice(uint256 newPrice)
        external
        onlyFeeder
        whenNotPaused
        validPrice(newPrice)
        nonReentrant
    {
        uint256 oldPrice = latestGoldPrice.price;
        latestGoldPrice = GoldPrice({
            price: newPrice,
            timestamp: block.timestamp,
            updater: msg.sender
        });

        emit GoldPriceUpdated(oldPrice, newPrice, block.timestamp);
    }

    /**
     * @dev Update country gold reserves
     * @param countryCode ISO 3166-1 alpha-2 country code
     * @param goldTonnes Gold reserves in tonnes (with 6 decimals for precision)
     */
    function updateCountryReserve(
        string calldata countryCode,
        uint256 goldTonnes
    )
        external
        onlyFeeder
        whenNotPaused
        validCountryCode(countryCode)
        nonReentrant
    {
        _updateCountryReserve(countryCode, goldTonnes);
        emit ReserveDataUpdated(countryCode, goldTonnes);
    }

    /**
     * @dev Internal function to update country reserve
     */
    function _updateCountryReserve(string memory countryCode, uint256 goldTonnes) internal {
        if (!countryReserves[countryCode].isActive) {
            activeCountries.push(countryCode);
            countryReserves[countryCode].isActive = true;
        }

        countryReserves[countryCode] = CountryReserve({
            countryCode: countryCode,
            goldTonnes: goldTonnes,
            lastUpdated: block.timestamp,
            updater: msg.sender,
            isActive: true
        });
    }

    /**
     * @dev Get total African gold reserves
     * @return Total gold reserves in tonnes
     */
    function getTotalAfricanReserves() external view returns (uint256) {
        uint256 total = 0;
        for (uint256 i = 0; i < activeCountries.length; i++) {
            total += countryReserves[activeCountries[i]].goldTonnes;
        }
        return total;
    }

    /**
     * @dev Get gold price in USD per gram
     * @return Price with 8 decimals
     */
    function getGoldPrice() external view returns (uint256) {
        require(block.timestamp - latestGoldPrice.timestamp <= MAX_PRICE_AGE, "BTNGGoldOracle: gold price too old");
        return latestGoldPrice.price;
    }

    /**
     * @dev Get country reserve data
     * @param countryCode ISO country code
     * @return goldTonnes The gold reserves in tonnes
     * @return lastUpdated The last update timestamp
     * @return isActive Whether the country is active
     */
    function getCountryReserve(string calldata countryCode)
        external
        view
        returns (uint256 goldTonnes, uint256 lastUpdated, bool isActive)
    {
        CountryReserve memory reserve = countryReserves[countryCode];
        require(reserve.isActive, "BTNGGoldOracle: country not found");

        return (reserve.goldTonnes, reserve.lastUpdated, reserve.isActive);
    }

    /**
     * @dev Calculate sovereign value for a country
     * @param countryCode ISO country code
     * @param population Country population
     * @return Sovereign value per person in BTNG
     */
    function calculateSovereignValue(
        string calldata countryCode,
        uint256 population
    )
        external
        view
        returns (uint256)
    {
        CountryReserve memory reserve = countryReserves[countryCode];
        require(reserve.isActive, "BTNGGoldOracle: country not found");
        require(population > 0, "BTNGGoldOracle: invalid population");

        // Sovereign value = (Gold reserves in grams * 1e6) / Population
        uint256 goldGrams = reserve.goldTonnes * 1000000; // Convert tonnes to grams
        return (goldGrams * 1000000) / population; // Multiply by 1e6 for precision
    }

    /**
     * @dev Request verification of gold operation
     * @param requestId Unique request identifier
     * @param operationType Type of operation (0=mint, 1=redeem)
     * @param amount Amount involved
     * @param goldBatchId Gold batch identifier
     */
    function requestVerification(
        bytes32 requestId,
        uint8 operationType,
        uint256 amount,
        string calldata goldBatchId
    )
        external
        onlyFeeder
        whenNotPaused
    {
        require(!verificationRequests[requestId], "BTNGGoldOracle: request already exists");

        verificationRequests[requestId] = true;

        // Basic validation logic (can be extended)
        bool isValid = _validateOperation(operationType, amount, goldBatchId);

        verificationResults[requestId] = isValid;

        emit VerificationCompleted(requestId, isValid);
    }

    /**
     * @dev Internal validation logic
     */
    function _validateOperation(
        uint8 operationType,
        uint256 amount,
        string calldata goldBatchId
    )
        internal
        view
        returns (bool)
    {
        // Basic validations
        if (amount == 0) return false;

        // Check if price data is fresh
        if (block.timestamp - latestGoldPrice.timestamp > MAX_PRICE_AGE) {
            return false;
        }

        // For minting operations, ensure we have sufficient reserves
        if (operationType == 0) { // Mint
            uint256 totalReserves = 0;
            for (uint256 i = 0; i < activeCountries.length; i++) {
                totalReserves += countryReserves[activeCountries[i]].goldTonnes;
            }
            uint256 requiredGrams = amount / 10**18;
            if (requiredGrams > totalReserves) return false;
        }

        return true;
    }

    /**
     * @dev Get verification result
     * @param requestId Request identifier
     * @return Verification result
     */
    function getVerificationResult(bytes32 requestId) external view returns (bool) {
        require(verificationRequests[requestId], "BTNGGoldOracle: request not found");
        return verificationResults[requestId];
    }

    /**
     * @dev Add authorized feeder
     * @param feeder Address to authorize
     */
    function addFeeder(address feeder) external onlyOwner {
        require(feeder != address(0), "BTNGGoldOracle: invalid feeder address");
        require(!authorizedFeeders[feeder], "BTNGGoldOracle: already feeder");

        authorizedFeeders[feeder] = true;
        emit OracleFeederAdded(feeder);
    }

    /**
     * @dev Remove authorized feeder
     * @param feeder Address to remove
     */
    function removeFeeder(address feeder) external onlyOwner {
        require(authorizedFeeders[feeder], "BTNGGoldOracle: feeder not authorized");

        authorizedFeeders[feeder] = false;
        emit OracleFeederRemoved(feeder);
    }

    /**
     * @dev Emergency pause
     */
    function pause() external onlyOwner {
        _pause();
    }

    /**
     * @dev Unpause after emergency
     */
    function unpause() external onlyOwner {
        _unpause();
    }

    /**
     * @dev Get active countries count
     */
    function getActiveCountriesCount() external view returns (uint256) {
        return activeCountries.length;
    }

    /**
     * @dev Get active country by index
     */
    function getActiveCountry(uint256 index) external view returns (string memory) {
        require(index < activeCountries.length, "BTNGGoldOracle: index out of bounds");
        return activeCountries[index];
    }

    /**
     * @dev Check if feeder is authorized
     */
    function isFeeder(address account) external view returns (bool) {
        return authorizedFeeders[account];
    }
}

